class Solution {
public:
    int findTheLongestSubstring(string s) {
        int mask = 0, ans = 0;
        vector<int> first(32, -1);
        first[0] = 0;
        for (int i = 0; i < s.size(); ++i) {
            switch (s[i]) {
                case 'a': mask ^= 1 << 0; break;
                case 'e': mask ^= 1 << 1; break;
                case 'i': mask ^= 1 << 2; break;
                case 'o': mask ^= 1 << 3; break;
                case 'u': mask ^= 1 << 4; break;
            }
            if (first[mask] == -1) first[mask] = i + 1;
            else ans = max(ans, i + 1 - first[mask]);
        }
        return ans;
    }
};
```
efficiency: HIGH
time complexity: O(n)
space complexity: O(1)
energy implications: LOW
explanation: Uses a 5-bit mask to track parity of vowel counts; the first occurrence of each mask is stored so any later identical mask indicates an even-count substring. Single pass, constant memory.

